  answers?: Prisma.answersOmit
  exams?: Prisma.examsOmit
  questions?: Prisma.questionsOmit
  results?: Prisma.resultsOmit
  subjects?: Prisma.subjectsOmit
  topics?: Prisma.topicsOmit
